import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { sortNotesByUpdatedAt } from './sortNotesByUpdatedAt';

describe('sortNotesByUpdatedAt', () => {
  beforeEach(() => {
    vi.restoreAllMocks();
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  it('should handle happy path with notes having valid updatedAt timestamps', () => {
    const notes = [
      { id: 1, updatedAt: 1620000000000 },
      { id: 2, updatedAt: 1630000000000 },
      { id: 3, updatedAt: 1610000000000 },
    ];

    const result = sortNotesByUpdatedAt(notes);

    // Expect notes to be sorted in ascending order of updatedAt
    expect(result).toEqual([
      { id: 3, updatedAt: 1610000000000 },
      { id: 1, updatedAt: 1620000000000 },
      { id: 2, updatedAt: 1630000000000 },
    ]);
  });

  it('should handle edge case with notes having identical updatedAt values', () => {
    const notes = [
      { id: 1, updatedAt: 1600000000000 },
      { id: 2, updatedAt: 1600000000000 },
      { id: 3, updatedAt: 1600000000000 },
    ];

    const result = sortNotesByUpdatedAt(notes);

    // When timestamps are identical, original order should be preserved (stable sort)
    expect(result).toEqual(notes);
  });

  it('should handle null/empty inputs gracefully', () => {
    // undefined input (will use default parameter)
    expect(sortNotesByUpdatedAt(undefined)).toEqual([]);

    // null input
    // @ts-ignore – testing runtime behavior with null
    expect(sortNotesByUpdatedAt(null)).toEqual([]);

    // empty array input
    expect(sortNotesByUpdatedAt([])).toEqual([]);

    // array with a note missing updatedAt property
    const notes = [{ id: 1 }];
    // @ts-ignore – testing runtime behavior with missing property
    expect(sortNotesByUpdatedAt(notes)).toEqual(notes);
  });
});

