import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { matchesSearchQuery } from '../src/matchesSearchQuery'

describe('matchesSearchQuery', () => {
  const note = {
    title: 'Meeting Notes',
    content: 'Discuss project timeline and milestones'
  }

  it('should handle happy path and return true when query matches title', () => {
    const result = matchesSearchQuery(note, 'Meeting')
    expect(result).toBe(true)
  })

  it('should handle edge case and return true when query matches content case‑insensitively', () => {
    const result = matchesSearchQuery(note, 'timeline')
    expect(result).toBe(true)
  })

  it('should handle null/empty inputs and return false', () => {
    const resultNull = matchesSearchQuery(null as any, 'any')
    const resultUndefined = matchesSearchQuery(undefined as any, 'any')
    const resultEmptyString = matchesSearchQuery(note, '')
    const resultZero = matchesSearchQuery(note, undefined as any)
    expect(resultNull).toBe(false)
    expect(resultUndefined).toBe(false)
    expect(resultEmptyString).toBe(false)
    expect(resultZero).toBe(false)
  })
})

